#include <iostream>  // Incluye la biblioteca estandar para entrada y salida de datos
using namespace std; // Permite usar nombres de la biblioteca estandar (cout, cin) sin prefijos

int main()
{ // Punto de inicio obligatorio de cualquier programa en C++

    // 1. DECLARACION DE VARIABLES
        // Definimos los contenedores de datos necesarios para el registro
            int opcionMenu;               // Guarda la seleccion del usuario en el menu principal
                int identificadorUsuario;     // Almacena el ID unico del beneficiario
                    int numeroComputadora;        // Identifica cual de las 20 PCs usara el ciudadano
                        int tiempoUsoMinutos;         // Registra la duracion de la sesion en el quiosco
                            int nivelEstudioSeleccionado; // Almacena el valor numerico del nivel educativo
                                char deseaContinuar;          // Controla si se repite el proceso de registro (S/N)

                                    // CICLO PRINCIPAL (DO-WHILE)
                                        // Se ejecuta al menos una vez y mantiene el sistema encendido mientras no se elija salir
                                            do
                                                {
                                                        // 2. INTERFAZ DE USUARIO: MENU PRINCIPAL
                                                                cout << "\n========================================" << endl;
                                                                        cout << "   SISTEMA DE ACCESO SIG-CONECTA" << endl;
                                                                                cout << "========================================" << endl;
                                                                                        cout << "1. Registrar ingreso" << endl;
                                                                                                cout << "2. Consultar disponibilidad de equipos" << endl;
                                                                                                        cout << "3. Salir del sistema" << endl;
                                                                                                                cout << "Seleccione una opcion: ";
                                                                                                                        cin >> opcionMenu; // Captura la decision del operador de la brigada

                                                                                                                                // ESTRUCTURA SELECTIVA (SWITCH)
                                                                                                                                        // Dirige el flujo del programa hacia la funcion especifica seleccionada
                                                                                                                                                switch (opcionMenu)
                                                                                                                                                        {
                                                                                                                                                                case 1: // Bloque para el registro de nuevos ciudadanos
                                                                                                                                                                            cout << "\n--- REGISTRO DE INGRESO ---" << endl;

                                                                                                                                                                                        // VALIDACION DE ID (CICLO WHILE)
                                                                                                                                                                                                    // Impide que se capturen IDs negativos o nulos (Integridad de datos)
                                                                                                                                                                                                                cout << "Ingrese el ID del usuario: ";
                                                                                                                                                                                                                            cin >> identificadorUsuario;
                                                                                                                                                                                                                                        while (identificadorUsuario <= 0)
                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                                    cout << "Error: el ID debe ser mayor que 0. Intente de nuevo: ";
                                                                                                                                                                                                                                                                                    cin >> identificadorUsuario; // Repite la solicitud hasta que sea valido
                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                            // VALIDACION DE PC
                                                                                                                                                                                                                                                                                                                        // Restringe el acceso unicamente a los equipos fisicos disponibles (1 al 20)
                                                                                                                                                                                                                                                                                                                                    cout << "Ingrese el numero de PC (1 a 20): ";
                                                                                                                                                                                                                                                                                                                                                cin >> numeroComputadora;
                                                                                                                                                                                                                                                                                                                                                            while (numeroComputadora < 1 || numeroComputadora > 20)
                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                        cout << "Error: el numero de PC debe estar entre 1 y 20. Intente de nuevo: ";
                                                                                                                                                                                                                                                                                                                                                                                                        cin >> numeroComputadora;
                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                // VALIDACION DE TIEMPO
                                                                                                                                                                                                                                                                                                                                                                                                                                            // Asegura que el registro de tiempo sea un valor logico positivo
                                                                                                                                                                                                                                                                                                                                                                                                                                                        cout << "Ingrese el tiempo de uso en minutos: ";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cin >> tiempoUsoMinutos;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                while (tiempoUsoMinutos <= 0)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            cout << "Error: el tiempo de uso debe ser mayor que 0. Intente de nuevo: ";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            cin >> tiempoUsoMinutos;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // SUBMENU DE NIVEL EDUCATIVO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // Utilizamos una entrada numerica para evitar fallas al leer textos con espacios
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            cout << "Nivel de estudio:" << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cout << "1. Primaria\n2. Secundaria\n3. Bachillerato\n4. Universidad" << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "Seleccione una opcion: ";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cin >> nivelEstudioSeleccionado;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Valida que la seleccion este dentro de las opciones del menu (1 al 4)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        while (nivelEstudioSeleccionado < 1 || nivelEstudioSeleccionado > 4)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "Error: opcion invalida. Seleccione un nivel del 1 al 4: ";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cin >> nivelEstudioSeleccionado;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // SALIDA DE DATOS: RESUMEN DE REGISTRO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Muestra la confirmacion visual de que la informacion fue procesada
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "\nRegistro guardado exitosamente." << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cout << "Resumen del acceso:" << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            cout << "ID del usuario: " << identificadorUsuario << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cout << "Numero de PC: " << numeroComputadora << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "Tiempo de uso: " << tiempoUsoMinutos << " minutos" << endl;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // TRADUCCION LOGICA (IF-ELSE IF)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Convierte el valor numerico interno a una etiqueta legible para el operador
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (nivelEstudioSeleccionado == 1)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "Nivel de estudio: Primaria" << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            else if (nivelEstudioSeleccionado == 2)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cout << "Nivel de estudio: Secundaria" << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                else if (nivelEstudioSeleccionado == 3)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            cout << "Nivel de estudio: Bachillerato" << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    else
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cout << "Nivel de estudio: Universidad" << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        break; // Sale del bloque de registro

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                case 2: // Bloque de consulta de recursos
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Mensaje estatico: fase de desarrollo 1 (sin base de datos real aun)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cout << "\n--- DISPONIBILIDAD DE EQUIPOS ---" << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "Actualmente hay 20 equipos disponibles de forma predeterminada." << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                break;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        case 3: // Bloque de salida segura
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "\nCerrando el subsistema de registro de emergencia..." << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                break;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        default: // Manejo de errores para entradas de menu invalidas
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "\nError: Opcion invalida. Por favor, seleccione 1, 2 o 3." << endl;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // 4. CONTROL DE CONTINUIDAD
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Si no se eligio "Salir", preguntamos si se atendera a otra persona en la fila
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (opcionMenu != 3)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "\nDesea registrar otro acceso? (S/N): ";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cin >> deseaContinuar;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // VALIDACION RIGUROSA DE CARACTER
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Asegura que el administrador solo responda S o N (mayuscula o minuscula)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    while (deseaContinuar != 'S' && deseaContinuar != 's' && deseaContinuar != 'N' && deseaContinuar != 'n')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cout << "Error: escriba solo S o N: ";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cin >> deseaContinuar;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            else
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                deseaContinuar = 'N'; // Si el usuario eligio salir en el menu, forzamos el fin del ciclo
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            } while (deseaContinuar == 'S' || deseaContinuar == 's'); // Evalua la condicion de repeticion

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // MENSAJE FINAL
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cout << "\nFin de la jornada de registro local en San Pedro de la Montana." << endl;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return 0; // El programa finaliza devolviendo 0 al sistema operativo (Exito)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }